    long long min_time = std::numeric_limits<long long>::max();
    int n = landStartTime.size();
    int m = waterStartTime.size();
    for (int i = 0; i < n; ++i) {
        for (int j = 0; j < m; ++j) {
            // Case 1: Land first
            long long land_end = landStartTime[i] + landDuration[i];
            long long water_start = waterStartTime[j];
            long long water_start_time = std::max(land_end, water_start);
            long long water_end = water_start_time + waterDuration[j];
            min_time = std::min(min_time, water_end);

